import Link from '@kyokuya/react-link'
import type { IMarkdownProps } from '@yozora/react-markdown'
import YozoraMarkdown from '@yozora/react-markdown'
import React from 'react'

const footnoteDefinitionsTitle: React.ReactNode = (
  <Link url="#footnote-definitions">
    <span id="footnote-definitions">footnote-definitions</span>
  </Link>
)

export const Markdown: React.FC<IMarkdownProps> = props => {
  return <YozoraMarkdown footnoteDefinitionsTitle={footnoteDefinitionsTitle} {...props} />
}

Markdown.propTypes = YozoraMarkdown.propTypes
export default Markdown
