import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'

export interface IKyokuyaCommentProps {
  /**
   *
   */
  className?: string
}

export class KyokuyaComment extends React.Component<IKyokuyaCommentProps> {
  public static propTypes = {
    className: PropTypes.string,
  }

  protected commentBox: React.RefObject<HTMLDivElement>

  constructor(props: IKyokuyaCommentProps) {
    super(props)
    this.commentBox = React.createRef() // Creates a reference to inject the <script> element
  }

  public override componentDidMount(): void {
    // The comment box is not prepared yet.
    if (this.commentBox.current == null) return

    // Only load the third-party scripts in production env.
    if (process.env.NODE_ENV !== 'production') return

    const scriptEl = document.createElement('script')
    scriptEl.setAttribute('src', 'https://utteranc.es/client.js')
    scriptEl.setAttribute('crossorigin', 'anonymous')
    scriptEl.setAttribute('async', 'true')
    scriptEl.setAttribute('repo', 'guanghechen/guanghechen.github.io')
    scriptEl.setAttribute('issue-term', 'pathname')
    scriptEl.setAttribute('label', 'comment')
    scriptEl.setAttribute('theme', 'github-light')
    this.commentBox.current.appendChild(scriptEl)
  }

  public override render(): React.ReactElement {
    const { className } = this.props
    return (
      <div className={cn('kyokuya-comment', className)}>
        <header className="kyokuya-comment__header">
          <h1>Comments</h1>
        </header>
        <div ref={this.commentBox} className="kyokuya-comment__main" />
      </div>
    )
  }
}

export default KyokuyaComment
