import type { IStorage } from '@kyokuya/react-storage'
import { usePersisDataEffect } from '@kyokuya/react-storage'
import type { ILayoutPostState } from '../context/state'

const persistKeys: Array<keyof ILayoutPostState> = [
  'darken',
  'brightness',
  'searchingKeyword',
  'searchingTagsVisible',
  'magicPanelVisible',
  'magicPanelActivated',
]

export function usePersistLayoutPostState(
  storage: IStorage<Partial<ILayoutPostState>> | null,
  data: ILayoutPostState,
): void {
  usePersisDataEffect<ILayoutPostState>(storage, data, persistKeys)
}

export default usePersistLayoutPostState
