import React from 'react'
import { ExternalLink } from './external'
import { InternalLink } from './internal'
import type { LinkProps } from './types'
import { linkPropTypes } from './types'
import './style.styl'

export function ReactLink(props: LinkProps): React.ReactElement | null {
  // Hash tag
  if (/^#/.test(props.url)) {
    return (
      <a title={props.title} href={props.url}>
        {props.children}
      </a>
    )
  }

  // External url
  if (/^(\w+:[/]{2})/.test(props.url)) {
    return <ExternalLink {...props} />
  }

  // Internal url
  return <InternalLink {...props} />
}

ReactLink.displayName = 'KyokuyaReactLink'
ReactLink.propTypes = linkPropTypes

export default ReactLink
