import type { APlayerOptions } from 'aplayer'
import cn from 'clsx'
import 'aplayer/dist/APlayer.min.css'
import React, { useEffect, useRef } from 'react'

export interface IReactAPlayerProps {
  /**
   * Options pass to APlayer.
   */
  options: APlayerOptions
  /**
   * CSS className.
   */
  className?: string
}

export function ReactAPlayer(props: IReactAPlayerProps): React.ReactElement {
  const { options, className } = props
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (containerRef.current == null) return
    const target: HTMLDivElement = containerRef.current

    // Dynamic import for ssr.
    void (async function (): Promise<void> {
      const { default: APlayer } = await import('aplayer')
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const aplayer = new APlayer({
        autoplay: false,
        listFolded: true,
        lrcType: 3,
        preload: 'metadata',
        theme: '#F57F17',
        ...options,
        container: target,
      })
    })()
  }, [options])

  return <div ref={containerRef} className={cn('kyokuya-react-aplayer', className)} />
}

export default ReactAPlayer
