import styled from '@emotion/styled'
import loadable from '@loadable/component'
import type { EcmaImport as IEcmaImport } from '@yozora/ast'
import type { ICodeRendererJsxProps } from '@yozora/react-code-renderer-jsx'
import type { ICodeRunner } from '@yozora/react-code-runners'
import { createUseJsxRunner } from '@yozora/react-code-runners'
import { useCallback, useEffect, useMemo, useState } from 'react'

const JsxRenderer = loadable<ICodeRendererJsxProps>(
  () => import('@yozora/react-code-renderer-jsx') as any,
)

export const useJsxRunner: (ecmaImports: IEcmaImport[]) => ICodeRunner = createUseJsxRunner(
  {
    styled,
    useCallback,
    useEffect,
    useMemo,
    useState,
  },
  [
    {
      regex: /^@kyokuya-demo\/([\s\S]+)$/,
      importFunc: match => () => import(`@kyokuya-demo/${match[1]}`),
    },
    {
      regex: /^@kyokuya\/_shared\/([\s\S]+)$/,
      importFunc: match => () => import(`@kyokuya/_shared/${match[1]}`),
    },
  ],
  JsxRenderer,
  'inline',
)
export default useJsxRunner
