import { css } from '@emotion/css'
import { ReactAPlayer } from '@kyokuya/react-aplayer'
import { LayoutPostActionType, LayoutPostContextType } from '@kyokuya/react-layout-post'
import Link from '@kyokuya/react-link'
import ReactMarkdown from '@kyokuya/react-markdown'
import { NavigateBeforeOutlined, NavigateNextOutlined } from '@mui/icons-material'
import EditIcon from '@mui/icons-material/Edit'
import type { Root as IRoot } from '@yozora/ast'
import { Theme, ThemeContextType } from '@yozora/core-react-theme'
import type { APlayerOptions } from 'aplayer'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'
import shallow from 'zustand/shallow'
import { useDependencyContext } from '@/core/context'

export interface IPostContentProps {
  title: string
  createAt: string
  updateAt: string
  timeToRead: string
  tags: string[]
  ast: IRoot
  slug: string
  aplayer?: APlayerOptions
  previous?: {
    title: string
    fields: {
      slug: string
    }
  }
  next?: {
    title: string
    fields: {
      slug: string
    }
  }
  /**
   * Whether to render the footer and footnote definitions.
   * @default true
   */
  shouldRenderFooter?: boolean
  className?: string
}

/**
 * Render contents of a markdown post.
 */
export const PostContent: React.FC<IPostContentProps> = props => {
  const {
    title,
    createAt,
    updateAt,
    timeToRead,
    tags,
    ast,
    slug,
    aplayer,
    previous,
    next,
    shouldRenderFooter = true,
    className,
  } = props
  const dontNeedFootnoteDefinitions = !shouldRenderFooter
  const { dispatch } = React.useContext(LayoutPostContextType)

  const classes = useStyles()
  const result = React.useMemo<React.ReactElement>(
    () => (
      <section
        className={cn(
          'kyokuya-post-content',
          'kyokuya-post__frosted-glass-panel',
          classes.container,
          className,
        )}
      >
        <header className="kyokuya-post-content__header">
          <h1>
            <Link title={title} url={slug} itemProp="url">
              <span itemProp="headline">{title}</span>
            </Link>
          </h1>
          <div className="kyokuya-post-content__header-meta">
            <div className="kyokuya-post-content__header-meta-date">
              <span key="createAt" itemProp="datePublished">
                {createAt} • &nbsp;🍻&nbsp;{timeToRead} read
              </span>
            </div>
            <div>
              {tags.length > 0 && (
                <React.Fragment>
                  🔖&nbsp;
                  {tags.map(tag => (
                    <span
                      key={tag}
                      className="kyokuya-post-content__header-meta-tag"
                      onClick={e => {
                        e.stopPropagation()
                        dispatch({
                          type: LayoutPostActionType.SEARCH_REQUEST,
                          payload: { keyword: '#' + tag },
                        })
                      }}
                    >
                      {tag}
                    </span>
                  ))}
                </React.Fragment>
              )}
            </div>
          </div>
        </header>
        {aplayer != null && (
          <ReactAPlayer className="kyokuya-post-content__aplayer" options={aplayer} />
        )}
        <div className="clearfix" />
        <article className="kyokuya-post-content__main">
          <ReactMarkdown ast={ast} dontNeedFootnoteDefinitions={dontNeedFootnoteDefinitions} />
        </article>
        {shouldRenderFooter && (
          <footer className="kyokuya-post-content__footer">
            <div className="kyokuya-post-content__footer-timestamp">
              <EditIcon />
              &nbsp;{updateAt}
            </div>
            <div className="kyokuya-post-content__footer-pagination">
              {previous != null && (
                <div className="kyokuya-post-content__footer-previous">
                  <Link url={previous.fields.slug}>
                    <NavigateBeforeOutlined />
                    <span>{previous.title}</span>
                  </Link>
                </div>
              )}
              {next != null && (
                <div className="kyokuya-post-content__footer-next">
                  <Link url={next.fields.slug}>
                    <span>{next.title}</span>
                    <NavigateNextOutlined />
                  </Link>
                </div>
              )}
            </div>
          </footer>
        )}
      </section>
    ),
    [
      title,
      createAt,
      updateAt,
      timeToRead,
      tags,
      ast,
      slug,
      aplayer,
      previous,
      next,
      shouldRenderFooter,
      className,
      dontNeedFootnoteDefinitions,
      dispatch,
      classes,
    ],
  )
  return result
}

PostContent.propTypes = {
  title: PropTypes.string.isRequired,
  createAt: PropTypes.string.isRequired,
  timeToRead: PropTypes.string.isRequired,
  tags: PropTypes.arrayOf(PropTypes.string.isRequired).isRequired,
  ast: PropTypes.any.isRequired,
  slug: PropTypes.string.isRequired,
  aplayer: PropTypes.any,
  previous: PropTypes.any,
  next: PropTypes.any,
  shouldRenderFooter: PropTypes.bool,
  className: PropTypes.string,
}

PostContent.displayName = 'KyokuyaLayoutPostPostContent'
export default PostContent

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => {
  const { theme, themeStyle } = React.useContext(ThemeContextType)
  return React.useMemo(() => {
    const { colors } = themeStyle
    return {
      container: css({
        '&&': {
          backgroundColor:
            theme === Theme.DARKEN ? colors.background.body : 'hsla(0deg, 0%, 100%, 0.9)',
        },
      }),
    }
  }, [theme, themeStyle])
}
