import cn from 'clsx'
import React from 'react'
import type { LinkProps } from './types'
import { linkPropTypes } from './types'

/**
 * Render an external link.
 */
export function ExternalLink(props: LinkProps): React.ReactElement {
  const {
    children,
    className,
    url,
    rel = 'noopener,noreferrer',
    target = '_blank',
    title,
    ...htmlProps
  } = props

  return (
    <a
      {...htmlProps}
      className={cn('kyokuya-react-link', 'kyokuya-react-link--external', className)}
      href={url}
      title={title}
      target={target}
      rel={rel}
    >
      {children}
    </a>
  )
}

ExternalLink.propTypes = linkPropTypes
ExternalLink.displayName = 'KyokuyaExternalLink'
